using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(cb => cb
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<ResearchTools>();
builder.Services.AddSingleton<NoteTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var researchTools = host.Services.GetRequiredService<ResearchTools>();
var noteTools = host.Services.GetRequiredService<NoteTools>();

var tools = new AIToolCollection
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.ReadUrl),
    AIFunctionFactory.Create(noteTools.SaveNote),
    AIFunctionFactory.Create(noteTools.GetNotes),
};

var agent = new ChatClientAgent(chatClient,
    """
    You are a research agent. Your job is to research a topic thoroughly and produce
    a well-structured summary. Follow this workflow:
    1. Search the web for relevant information on the topic.
    2. Read the most promising URLs to get detailed content.
    3. Save important findings as notes with descriptive titles.
    4. After gathering enough information, retrieve all your notes and synthesize
       them into a comprehensive summary.
    Always cite your sources. Be thorough but concise.
    """,
    tools);

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 15,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine();

/// <summary>Tools for searching the web and reading page content.</summary>
public sealed class ResearchTools
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
        },
    };

    [Description("Search the web for a query and return a list of results with titles, snippets, and URLs.")]
    public static async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            return ParseDuckDuckGoResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Read the text content of a web page at the given URL.")]
    public static async Task<string> ReadUrl(
        [Description("The URL to read")] string url)
    {
        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);
            return text.Length > 4000 ? text[..4000] + "\n... (truncated)" : text;
        }
        catch (Exception ex)
        {
            return $"Failed to read URL: {ex.Message}";
        }
    }

    private static string ParseDuckDuckGoResults(string html)
    {
        var results = new List<string>();
        var span = html.AsSpan();
        int pos = 0;

        while (results.Count < 8)
        {
            int linkStart = html.IndexOf("class=\"result__a\"", pos, StringComparison.Ordinal);
            if (linkStart < 0) break;

            int hrefStart = html.LastIndexOf("href=\"", linkStart, Math.Min(linkStart, 200), StringComparison.Ordinal);
            if (hrefStart < 0) { pos = linkStart + 1; continue; }
            hrefStart += 6;
            int hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd < 0) { pos = linkStart + 1; continue; }
            var href = html[hrefStart..hrefEnd];

            int titleEnd = html.IndexOf("</a>", linkStart, StringComparison.Ordinal);
            int titleStart = html.IndexOf('>', linkStart) + 1;
            var title = titleStart > 0 && titleEnd > titleStart
                ? StripHtml(html[titleStart..titleEnd]).Trim()
                : "(no title)";

            int snippetStart = html.IndexOf("class=\"result__snippet\"", titleEnd > 0 ? titleEnd : linkStart + 1, StringComparison.Ordinal);
            var snippet = "";
            if (snippetStart >= 0)
            {
                int sStart = html.IndexOf('>', snippetStart) + 1;
                int sEnd = html.IndexOf("</a>", sStart, StringComparison.Ordinal);
                if (sEnd < 0) sEnd = html.IndexOf("</td>", sStart, StringComparison.Ordinal);
                if (sStart > 0 && sEnd > sStart)
                    snippet = StripHtml(html[sStart..sEnd]).Trim();
            }

            results.Add($"Title: {title}\nURL: {System.Net.WebUtility.UrlDecode(href)}\nSnippet: {snippet}\n");
            pos = snippetStart > 0 ? snippetStart + 1 : linkStart + 1;
        }

        return results.Count > 0
            ? string.Join("\n---\n", results)
            : "No results found.";
    }

    private static string StripHtml(string html)
    {
        var text = System.Text.RegularExpressions.Regex.Replace(html, "<script[^>]*>[\\s\\S]*?</script>", "", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        text = System.Text.RegularExpressions.Regex.Replace(text, "<style[^>]*>[\\s\\S]*?</style>", "", System.Text.RegularExpressions.RegexOptions.IgnoreCase);
        text = System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", " ");
        text = System.Net.WebUtility.HtmlDecode(text);
        text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
        return text.Trim();
    }
}

/// <summary>Tools for taking and retrieving research notes.</summary>
public sealed class NoteTools
{
    private readonly List<(string Title, string Content)> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note including key facts and source URLs")] string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes to review findings before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n---\n\n", _notes.Select((n, i) =>
            $"Note {i + 1}: {n.Title}\n{n.Content}"));
    }
}

