using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(cb => cb
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<NoteTools>();

using var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteTools = host.Services.GetRequiredService<NoteTools>();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(ResearchTools.SearchWeb),
    AIFunctionFactory.Create(ResearchTools.ReadUrl),
    AIFunctionFactory.Create(noteTools.SaveNote),
    AIFunctionFactory.Create(noteTools.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly and produce
        a well-structured summary. Follow this workflow:
        1. Search the web for relevant information on the topic.
        2. Read the most promising URLs to get detailed content.
        3. Save important findings as notes with descriptive titles.
        4. After gathering enough information, retrieve all your notes and synthesize
           them into a comprehensive summary.
        Always cite your sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    tools: tools);

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

