import subprocess, os, glob as g
for d in g.glob(os.path.expanduser('~/.nuget/packages/microsoft.extensions.ai.openai/*/lib/net10.0/*.dll')):
    print(d)
    result = subprocess.run(['strings', d], capture_output=True, text=True)
    for l in sorted(set(result.stdout.split('\n'))):
        if 'UseOpenAI' in l or 'AddOpenAI' in l or ('ChatClient' in l and 'Extension' in l):
            print(f'  {l}')
" | head -20

